import React from 'react';

import CustomCard from '../components/CustomCard';
import CollapsedText from '../components/CollapsedText';
import Button from '../components/CustomButton';
import ReactPlayer from 'react-player';

import { games } from '../constants';

function Home() {

  const sparkle = games[0];

  return (
    <div className='home-app'>
    <CustomCard content={
      <>
        <CustomCard content={
        <ReactPlayer
          url={sparkle.url}
          controls
          width='95%'
          height='95%'
          loop
          muted
        />
      }
        className="custom-card colored-card"
      />

      <CustomCard content={
        <CollapsedText
          title={sparkle.title}
          description={sparkle.description}
          content={
            <Button
              buttonLabel={sparkle.buttonLabel}
              onClickNavigate={sparkle.onClickNavigate}
            />
          }
        />
      }
        className="custom-card-auto-height colored-card"
      />
      </>
    }/>
    </div>
  );
}

export default Home;
